94	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
95	{
96		uint8_t x, y, fg, bg;
97		printf("\033[H"); // move cursor to 0,0
98		printf("2048.c %17u pts\n\n", score);
99		for (y = 0; y < SIZE; y++)
100		{
101			for (x = 0; x < SIZE; x++)
102			{
103				// send the addresses of the foreground and background variables,
104				// so that they can be modified by the getColors function
105				getColors(board[x][y], scheme, &fg, &bg);
106				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
107				printf("       ");
108				printf("\033[m"); // reset all modes
109			}
110			printf("\n");
111			for (x = 0; x < SIZE; x++)
112			{
113				getColors(board[x][y], scheme, &fg, &bg);
114				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
115				if (board[x][y] != 0)
116				{
117					uint32_t number = 1 << board[x][y];
118					uint8_t t = 7 - getDigitCount(number);
119					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
120				}
121				else
122				{
123					printf("   ·   ");
124				}
125				printf("\033[m"); // reset all modes
126			}
127			printf("\n");
128			for (x = 0; x < SIZE; x++)
129			{
130				getColors(board[x][y], scheme, &fg, &bg);
131				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
132				printf("       ");
133				printf("\033[m"); // reset all modes
134			}
135			printf("\n");
136		}
137		printf("\n");
138		printf("        ←,↑,→,↓ or q        \n");
139		printf("\033[A"); // one line up
140	}
