226	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
227	{
228		bool success = false;
229		uint8_t x;
230		for (x = 0; x < SIZE; x++)
231		{
232			success |= slideArray(board[x], score);
233		}
234		return success;
235	}
