237	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
238	{
239		bool success;
240		rotateBoard(board);
241		success = moveUp(board, score);
242		rotateBoard(board);
243		rotateBoard(board);
244		rotateBoard(board);
245		return success;
246	}
