248	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
249	{
250		bool success;
251		rotateBoard(board);
252		rotateBoard(board);
253		success = moveUp(board, score);
254		rotateBoard(board);
255		rotateBoard(board);
256		return success;
257	}
258	
259	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
260	{
261		bool success;
262		rotateBoard(board);
263		rotateBoard(board);
264		rotateBoard(board);
265		success = moveUp(board, score);
266		rotateBoard(board);
267		return success;
268	}
