270	bool findPairDown(uint8_t board[SIZE][SIZE])
271	{
272		bool success = false;
273		uint8_t x, y;
274		for (x = 0; x < SIZE; x++)
275		{
276			for (y = 0; y < SIZE - 1; y++)
277			{
278				if (board[x][y] == board[x][y + 1])
279					return true;
280			}
281		}
282		return success;
283	}
284	
285	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
286	{
287		uint8_t x, y;
288		uint8_t count = 0;
289		for (x = 0; x < SIZE; x++)
290		{
291			for (y = 0; y < SIZE; y++)
292			{
293				if (board[x][y] == 0)
294				{
295					count++;
296				}
297			}
298		}
299		return count;
300	}
301	
302	bool gameEnded(uint8_t board[SIZE][SIZE])
303	{
304		bool ended = true;
305		if (countEmpty(board) > 0)
306			return false;
307		if (findPairDown(board))
308			return false;
309		rotateBoard(board);
310		if (findPairDown(board))
311			ended = false;
312		rotateBoard(board);
313		rotateBoard(board);
314		rotateBoard(board);
315		return ended;
316	}
