318	/* Helpers for specifying `addRandom`. Constant cell indices are used throughout
319	 * because CBMC's history variables (`__CPROVER_old`) do not support array
320	 * snapshots under a quantified index, so the 4x4 board is enumerated explicitly.
321	 *
322	 *  - CELL_UNCHANGED_OR_NEW(r,c): cell (r,c) either keeps its old value, or was
323	 *    empty (0) and now holds a freshly spawned tile (1 or 2).
324	 *  - CELL_CHANGED(r,c): 1 if cell (r,c) differs from its old value, else 0.
325	 *  - WAS_EMPTY(r,c): true iff cell (r,c) held 0 before the call. */
326	#define CELL_UNCHANGED_OR_NEW(r, c)                       \
327		(board[r][c] == __CPROVER_old(board[r][c]) ||         \
328		 (__CPROVER_old(board[r][c]) == 0 &&                  \
329		  (board[r][c] == 1 || board[r][c] == 2)))
330	#define CELL_CHANGED(r, c) (board[r][c] != __CPROVER_old(board[r][c]) ? 1 : 0)
331	#define WAS_EMPTY(r, c) (__CPROVER_old(board[r][c]) == 0)
332	
333	/* Number of board cells that changed value over the call. */
334	#define NUM_CHANGED                                                      \
335		(CELL_CHANGED(0, 0) + CELL_CHANGED(0, 1) + CELL_CHANGED(0, 2) +      \
336		 CELL_CHANGED(0, 3) + CELL_CHANGED(1, 0) + CELL_CHANGED(1, 1) +      \
337		 CELL_CHANGED(1, 2) + CELL_CHANGED(1, 3) + CELL_CHANGED(2, 0) +      \
338		 CELL_CHANGED(2, 1) + CELL_CHANGED(2, 2) + CELL_CHANGED(2, 3) +      \
339		 CELL_CHANGED(3, 0) + CELL_CHANGED(3, 1) + CELL_CHANGED(3, 2) +      \
340		 CELL_CHANGED(3, 3))
341	
342	/* True iff the board had at least one empty cell before the call. */
343	#define HAD_EMPTY                                                        \
344		(WAS_EMPTY(0, 0) || WAS_EMPTY(0, 1) || WAS_EMPTY(0, 2) ||            \
345		 WAS_EMPTY(0, 3) || WAS_EMPTY(1, 0) || WAS_EMPTY(1, 1) ||            \
346		 WAS_EMPTY(1, 2) || WAS_EMPTY(1, 3) || WAS_EMPTY(2, 0) ||            \
347		 WAS_EMPTY(2, 1) || WAS_EMPTY(2, 2) || WAS_EMPTY(2, 3) ||            \
348		 WAS_EMPTY(3, 0) || WAS_EMPTY(3, 1) || WAS_EMPTY(3, 2) ||            \
349		 WAS_EMPTY(3, 3))
350	
351	void addRandom(uint8_t board[SIZE][SIZE])
352	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
353	__CPROVER_assigns(__CPROVER_object_whole(board))
354	/* Every cell is either unchanged or a newly spawned tile in a formerly empty
355	 * cell -- in particular, no non-empty tile is ever overwritten or cleared. */
356	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 0))
357	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 1))
358	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 2))
359	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(0, 3))
360	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 0))
361	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 1))
362	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 2))
363	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(1, 3))
364	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 0))
365	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 1))
366	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 2))
367	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(2, 3))
368	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 0))
369	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 1))
370	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 2))
371	__CPROVER_ensures(CELL_UNCHANGED_OR_NEW(3, 3))
372	/* Exactly one tile is spawned when the board had room, and none otherwise. */
373	__CPROVER_ensures(NUM_CHANGED == (HAD_EMPTY ? 1 : 0))
374	{
375		static bool initialized = false;
376		uint8_t x, y;
377		uint8_t r, len = 0;
378		uint8_t n, list[SIZE * SIZE][2];
379	
380		if (!initialized)
381		{
382			srand(time(NULL));
383			initialized = true;
384		}
385	
386		for (x = 0; x < SIZE; x++)
387		{
388			for (y = 0; y < SIZE; y++)
389			{
390				if (board[x][y] == 0)
391				{
392					list[len][0] = x;
393					list[len][1] = y;
394					len++;
395				}
396			}
397		}
398	
399		if (len > 0)
400		{
401			r = rand() % len;
402			x = list[r][0];
403			y = list[r][1];
404			n = (rand() % 10) / 9 + 1;
405			board[x][y] = n;
406		}
407	}
