409	void initBoard(uint8_t board[SIZE][SIZE])
410	{
411		uint8_t x, y;
412		for (x = 0; x < SIZE; x++)
413		{
414			for (y = 0; y < SIZE; y++)
415			{
416				board[x][y] = 0;
417			}
418		}
419		addRandom(board);
420		addRandom(board);
421	}
