423	void setBufferedInput(bool enable)
424	{
425		static bool enabled = true;
426		static struct termios old;
427		struct termios new;
428	
429		if (enable && !enabled)
430		{
431			// restore the former settings
432			tcsetattr(STDIN_FILENO, TCSANOW, &old);
433			// set the new state
434			enabled = true;
435		}
436		else if (!enable && enabled)
437		{
438			// get the terminal settings for standard input
439			tcgetattr(STDIN_FILENO, &new);
440			// we want to keep the old setting to restore them at the end
441			old = new;
442			// disable canonical mode (buffered i/o) and local echo
443			new.c_lflag &= (~ICANON & ~ECHO);
444			// set the new settings immediately
445			tcsetattr(STDIN_FILENO, TCSANOW, &new);
446			// set the new state
447			enabled = false;
448		}
449	}
