451	bool testSucceed()
452	{
453		uint8_t array[SIZE];
454		// these are exponents with base 2 (1=2 2=4 3=8)
455		// data holds per line: 4x IN, 4x OUT, 1x POINTS
456		uint8_t data[] = {
457			0, 0, 0, 1, 1, 0, 0, 0, 0,
458			0, 0, 1, 1, 2, 0, 0, 0, 4,
459			0, 1, 0, 1, 2, 0, 0, 0, 4,
460			1, 0, 0, 1, 2, 0, 0, 0, 4,
461			1, 0, 1, 0, 2, 0, 0, 0, 4,
462			1, 1, 1, 0, 2, 1, 0, 0, 4,
463			1, 0, 1, 1, 2, 1, 0, 0, 4,
464			1, 1, 0, 1, 2, 1, 0, 0, 4,
465			1, 1, 1, 1, 2, 2, 0, 0, 8,
466			2, 2, 1, 1, 3, 2, 0, 0, 12,
467			1, 1, 2, 2, 2, 3, 0, 0, 12,
468			3, 0, 1, 1, 3, 2, 0, 0, 4,
469			2, 0, 1, 1, 2, 2, 0, 0, 4};
470		uint8_t *in, *out, *points;
471		uint8_t t, tests;
472		uint8_t i;
473		bool success = true;
474		uint32_t score;
475	
476		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
477		for (t = 0; t < tests; t++)
478		{
479			in = data + t * (2 * SIZE + 1);
480			out = in + SIZE;
481			points = in + 2 * SIZE;
482			for (i = 0; i < SIZE; i++)
483			{
484				array[i] = in[i];
485			}
486			score = 0;
487			slideArray(array, &score);
488			for (i = 0; i < SIZE; i++)
489			{
490				if (array[i] != out[i])
491				{
492					success = false;
493				}
494			}
495			if (score != *points)
496			{
497				success = false;
498			}
499			if (success == false)
500			{
501				for (i = 0; i < SIZE; i++)
502				{
503					printf("%u ", in[i]);
504				}
505				printf("=> ");
506				for (i = 0; i < SIZE; i++)
507				{
508					printf("%u ", array[i]);
509				}
510				printf("(%u points) expected ", score);
511				for (i = 0; i < SIZE; i++)
512				{
513					printf("%u ", in[i]);
514				}
515				printf("=> ");
516				for (i = 0; i < SIZE; i++)
517				{
518					printf("%u ", out[i]);
519				}
520				printf("(%u points)\n", *points);
521				break;
522			}
523		}
524		if (success)
525		{
526			printf("All %u tests executed successfully\n", tests);
527		}
528		return success;
529	}
