540	int main(int argc, char *argv[])
541	{
542		uint8_t board[SIZE][SIZE];
543		uint8_t scheme = 0;
544		uint32_t score = 0;
545		int c;
546		bool success;
547	
548		// handle the command line options
549		if (argc > 1)
550		{
551			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
552			{
553				printf("Usage: 2048 [OPTION] | [MODE]\n");
554				printf("Play the game 2048 in the console\n\n");
555				printf("Options:\n");
556				printf("  -h,  --help       Show this help message.\n");
557				printf("  -v,  --version    Show version number.\n\n");
558				printf("Modes:\n");
559				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
560				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
561				return EXIT_SUCCESS;
562			}
563			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
564			{
565				printf("2048.c version %s\n", VERSION);
566				return EXIT_SUCCESS;
567			}
568			else if (strcmp(argv[1], "blackwhite") == 0)
569			{
570				scheme = 1;
571			}
572			else if (strcmp(argv[1], "bluered") == 0)
573			{
574				scheme = 2;
575			}
576			else if (strcmp(argv[1], "whiteblack") == 0)
577			{
578				scheme = 3;
579			}
580			else if (strcmp(argv[1], "test") == 0)
581			{
582				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
583			}
584			else
585			{
586				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
587				return EXIT_FAILURE;
588			}
589		}
590	
591		// make cursor invisible, erase entire screen
592		printf("\033[?25l\033[2J");
593	
594		// register signal handler for when ctrl-c is pressed
595		signal(SIGINT, signal_callback_handler);
596	
597		initBoard(board);
598		setBufferedInput(false);
599		drawBoard(board, scheme, score);
600		while (true)
601		{
602			c = getchar();
603			if (c == EOF)
604			{
605				puts("\nError! Cannot read keyboard input!");
606				break;
607			}
608			switch (c)
609			{
610			case 52:  // '4' key
611			case 97:  // 'a' key
612			case 104: // 'h' key
613			case 68:  // left arrow
614				success = moveLeft(board, &score);
615				break;
616			case 54:  // '6' key
617			case 100: // 'd' key
618			case 108: // 'l' key
619			case 67:  // right arrow
620				success = moveRight(board, &score);
621				break;
622			case 56:  // '8' key
623			case 119: // 'w' key
624			case 107: // 'k' key
625			case 65:  // up arrow
626				success = moveUp(board, &score);
627				break;
628			case 50:  // '2' key
629			case 115: // 's' key
630			case 106: // 'j' key
631			case 66:  // down arrow
632				success = moveDown(board, &score);
633				break;
634			default:
635				success = false;
636			}
637			if (success)
638			{
639				drawBoard(board, scheme, score);
640				usleep(150 * 1000); // 150 ms
641				addRandom(board);
642				drawBoard(board, scheme, score);
643				if (gameEnded(board))
644				{
645					printf("         GAME OVER          \n");
646					break;
647				}
648			}
649			if (c == 'q')
650			{
651				printf("        QUIT? (y/n)         \n");
652				c = getchar();
653				if (c == 'y')
654				{
655					break;
656				}
657				drawBoard(board, scheme, score);
658			}
659			if (c == 'r')
660			{
661				printf("       RESTART? (y/n)       \n");
662				c = getchar();
663				if (c == 'y')
664				{
665					initBoard(board);
666					score = 0;
667				}
668				drawBoard(board, scheme, score);
669			}
670		}
671		setBufferedInput(true);
672	
673		// make cursor visible, reset all modes
674		printf("\033[?25h\033[m");
675	
676		return EXIT_SUCCESS;
677	}
